// ===============================================
// Transformar rows MSSQL → 2D array para GSheet
// ===============================================
// El nodo GSheet espera msg.payload como array de arrays:
//   [["col1","col2",...], ["val1","val2",...], ...]
// No incluimos cabecera — la sheet ya tiene headers congelados

var rows = msg.payload;
var sync_uuid = msg.sync_uuid || 'N/A';
var startDate = msg.startDate || '';
var endDate = msg.endDate || '';
var timestamp = new Date().toISOString();
var periodo = startDate + '-' + endDate;

// Guardar metadata para el nodo de resultado
msg._syncInfo = {
  sync_uuid: sync_uuid,
  periodo: periodo,
  timestamp: timestamp
};

if (!rows || !Array.isArray(rows) || rows.length === 0) {
  node.warn('[Sync-SS-v2] Sin datos para sync. Se omite escritura.');
  msg._syncInfo.empty = true;
  msg.payload = null;  // null → no se escribe nada
  return msg;
}

// Construir array 2D: cada fila es un array de 9 columnas
var data = [];
for (var i = 0; i < rows.length; i++) {
  var r = rows[i];
  var debe = parseFloat(r.DEBE_PERIODO) || 0;
  var haber = parseFloat(r.HABER_PERIODO) || 0;
  var saldo = debe - haber;

  data.push([
    r.CODIGO || '',                          // A: CODIGO
    r.CUENTA || '',                          // B: CUENTA
    r.NRubro || '',                          // C: RUBRO
    debe,                                     // D: DEBE_PERIODO
    haber,                                    // E: HABER_PERIODO
    saldo,                                    // F: SALDO_PERIODO
    periodo,                                  // G: PERIODO
    timestamp,                                // H: FECHA_SYNC
    sync_uuid                                 // I: SYNC_UUID
  ]);
}

// Formato 2D array → GSheet lo detecta automáticamente
msg.payload = data;

msg._syncInfo.rowCount = data.length;
node.warn('[Sync-SS-v2] ' + data.length + ' filas preparadas para Google Sheets. UUID=' + sync_uuid);
return msg;

// ===============================================
// Procesar resultado del sync a Google Sheets
// ===============================================
var info = msg._syncInfo || {};

if (info.empty) {
  node.warn('[Sync-SS-v2] Sync omitido: sin datos en el periodo ' + (info.periodo || '?'));
  return msg;
}

// El GSheet node devuelve en msg.payload la respuesta de la API
// Si hay error, msg.error tendrá el mensaje
if (msg.error) {
  node.error('[Sync-SS-v2] ERROR al escribir en Google Sheets: ' + msg.error);
  return msg;
}

var updatedRange = '';
if (msg.payload && msg.payload.updates) {
  updatedRange = msg.payload.updates.updatedRange || '';
}

node.warn('[Sync-SS-v2] ✅ Sync exitoso a Google Sheets');
node.warn('[Sync-SS-v2]    UUID: ' + (info.sync_uuid || '?'));
node.warn('[Sync-SS-v2]    Periodo: ' + (info.periodo || '?'));
node.warn('[Sync-SS-v2]    Filas: ' + (info.rowCount || 0));
node.warn('[Sync-SS-v2]    Rango: ' + updatedRange);

// Pasar metadata para nodos siguientes si se agregaran
msg._syncResult = {
  success: true,
  uuid: info.sync_uuid,
  periodo: info.periodo,
  rows: info.rowCount,
  range: updatedRange,
  timestamp: info.timestamp
};

return msg;
